function safetyDefaults(overrides = {}) {
  return {
    blockAdvance: false,
    skipLead: false,
    dedupeCheckFailed: false,
    w11SendCheckFailed: false,
    callTaskExists: false,
    smsTaskExists: false,
    reviewTaskExists: false,
    emailLogExists: false,
    callTaskComplete: false,
    smsTaskComplete: false,
    reviewTaskComplete: false,
    emailComplete: false,
    emailAlreadyLogged: false,
    emailSentThisRun: false,
    ...overrides,
  };
}

function debugSkip(ctx, skipReason) {
  return safetyDefaults({
    ...ctx,
    skip: true,
    skipReason,
    leadId: ctx?.leadId || '',
    currentStep: ctx?.currentStep || '',
    needsCallTask: ctx?.needsCallTask === true,
    needsSmsTask: ctx?.needsSmsTask === true,
    needsEmailSend: ctx?.needsEmailSend === true,
    needsReviewTask: ctx?.needsReviewTask === true,
    callTaskExists: ctx?.callTaskExists === true,
    smsTaskExists: ctx?.smsTaskExists === true,
    reviewTaskExists: ctx?.reviewTaskExists === true,
    emailLogExists: ctx?.emailLogExists === true,
    blockAdvance: ctx?.blockAdvance === true,
    skipLead: ctx?.skipLead === true,
    dedupeCheckFailed: ctx?.dedupeCheckFailed === true,
    w11SendCheckFailed: ctx?.w11SendCheckFailed === true,
  });
}
function safeNodeItems(nodeName) {
  try { return $(nodeName).all(); } catch (e) { return []; }
}
function safeNodeFirst(nodeName) {
  try { return $(nodeName).first().json; } catch (e) { return {}; }
}

const cfg = safeNodeFirst('Re-engagement Sequence Config');
const leadItems = safeNodeItems('Query Stalled Leads');

const failedEstLookupLeadIds = new Set();
for (const errItem of safeNodeItems('Stop — EST Lookup Failed')) {
  const ej = errItem.json || {};
  const id = ej.Id || ej.id || ej.leadId;
  if (id) failedEstLookupLeadIds.add(String(id));
}

const estByKey = {};
for (const r of safeNodeItems('Find Stalled EST Record')) {
  const rj = r.json;
  if (rj && rj.Stalled_Sequence_Key__c) estByKey[String(rj.Stalled_Sequence_Key__c)] = rj;
}

const today = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Los_Angeles' });
const currentHour = Number(
  new Intl.DateTimeFormat('en-US', {
    timeZone: 'America/Los_Angeles',
    hour: '2-digit',
    hourCycle: 'h23',
  }).format(new Date())
);
const nowISO = new Date().toISOString();

const NEXT_STEP = {
  '': 'ST_Day0',
  NONE: 'ST_Day0',
  ST_Day0: 'ST_Day14',
  ST_Day14: 'ST_Day28',
  ST_Day28: 'ST_Day42',
  ST_Day42: 'Done',
};
const ACTIONS = {
  ST_Day0: { callTask: true, smsTask: false, sendEmail: true, reviewTask: false },
  ST_Day14: { callTask: true, smsTask: true, sendEmail: false, reviewTask: false },
  ST_Day28: { callTask: true, smsTask: false, sendEmail: true, reviewTask: false },
  ST_Day42: { callTask: false, smsTask: true, sendEmail: true, reviewTask: true },
};
const DAYS_UNTIL_NEXT = { ST_Day0: 14, ST_Day14: 14, ST_Day28: 14, ST_Day42: 0 };
const STEP_ORDER = ['ST_Day0', 'ST_Day14', 'ST_Day28', 'ST_Day42', 'Done'];

function buildLeadContext(lead, estRaw, currentStep, estId) {
  const seqKey = String(lead.Id) + '_Stalled';
  const leadName = (String(lead.FirstName || '') + ' ' + String(lead.LastName || '')).trim();
  const stepIdx = STEP_ORDER.indexOf(currentStep);
  const nextStep = stepIdx >= 0 && stepIdx < STEP_ORDER.length - 1 ? STEP_ORDER[stepIdx + 1] : 'Done';
  const isLastStep = currentStep === 'ST_Day42';
  const daysToNext = DAYS_UNTIL_NEXT[currentStep] || 0;
  const rawNextDate = new Date();
  rawNextDate.setDate(rawNextDate.getDate() + daysToNext);
  const rawNextDateStr = daysToNext > 0 ? rawNextDate.toISOString() : null;

  return safetyDefaults({
    mode: 'send',
    leadId: String(lead.Id),
    firstName: String(lead.FirstName || 'there'),
    lastName: String(lead.LastName || ''),
    leadName,
    email: String(lead.Email || '').trim(),
    leadStatus: String(lead.Status || ''),
    estId: estId || '',
    sequenceKey: seqKey,
    stalledStartAt: estRaw ? String(estRaw.Stalled_Start_At__c || nowISO) : nowISO,
    preserveLastEmailSentAt: estRaw ? String(estRaw.Stalled_Last_Sequence_Email_Sent_At__c || '') : '',
    currentStep,
    nextStep,
    isLastStep,
    daysToNext,
    rawNextDateStr,
    exampleOwnerId: String(cfg.exampleOwnerId),
    calendlyLink: String(cfg.calendlyLink || ''),
    colleagueSignatureHtml: String(cfg.colleagueSignatureHtml || ''),
    ccEmail: String(cfg.senderCcEmail || ''),
    senderCcEmail: String(cfg.senderCcEmail || ''),
    w11Timezone: 'America/Los_Angeles',
    w11CheckDateTime: nowISO,
    currentHour,
    today,
    needsCallTask: !!(ACTIONS[currentStep] || {}).callTask,
    needsSmsTask: !!(ACTIONS[currentStep] || {}).smsTask,
    needsEmailSend: !!(ACTIONS[currentStep] || {}).sendEmail,
    needsReviewTask: !!(ACTIONS[currentStep] || {}).reviewTask,
  });
}

const results = [];
for (const leadItem of leadItems) {
  const lead = leadItem.json;
  if (lead.Engagement_Status__c !== 'Stalled') continue;

  if (failedEstLookupLeadIds.has(String(lead.Id))) continue;

  const rawEmail = String(lead.Email || '').trim();
  if (!rawEmail || !rawEmail.includes('@')) {
    results.push({
      json: debugSkip(
        {
          leadId: String(lead.Id),
          firstName: String(lead.FirstName || ''),
          lastName: String(lead.LastName || ''),
          email: rawEmail,
          leadStatus: String(lead.Status || ''),
        },
        'Skipped because Lead is Stalled but has no valid email for email step.'
      ),
    });
    continue;
  }

  const seqKey = String(lead.Id) + '_Stalled';
  const estRaw = estByKey[seqKey] || null;

  if (estRaw) {
    const stStatus = String(estRaw.Stalled_Sequence_Status__c || '');
    if (['Paused', 'Stopped', 'Completed'].includes(stStatus)) continue;

    const lastSent = String(estRaw.Stalled_Last_Sequence_Step_Sent__c || '').trim();
    const currentStep = NEXT_STEP[lastSent] || 'ST_Day0';
    if (currentStep === 'Done') continue;

    const nextDue = String(estRaw.Stalled_Next_Follow_Up_Date__c || '');
    const lastEmailSent = estRaw.Stalled_Last_Sequence_Email_Sent_At__c;
    const isFirstStepNeverSent = currentStep === 'ST_Day0' && !lastSent && !lastEmailSent;
    if (nextDue && nextDue > today && !isFirstStepNeverSent) continue;

    const stepActions = ACTIONS[currentStep] || {};
    if (stepActions.sendEmail && estRaw.Stalled_Last_Sequence_Email_Sent_At__c) {
      const hoursSince = (Date.now() - new Date(estRaw.Stalled_Last_Sequence_Email_Sent_At__c).getTime()) / 3600000;
      if (hoursSince < 25) continue;
    }

    results.push({ json: buildLeadContext(lead, estRaw, currentStep, String(estRaw.Id)) });
  } else {
    results.push({ json: buildLeadContext(lead, null, 'ST_Day0', '') });
  }
}
return results.length > 0 ? results : [{ json: { noEligibleLeads: true } }];

const results = [];
const normItems = $('Normalize Lead + Stalled EST').all().filter((i) => i.json.mode === 'init');
const w11Items = $input.all();
for (let i = 0; i < normItems.length; i++) {
  const ctx = normItems[i].json;
  const w11 = w11Items[i]?.json || {};
  let nextDueDateStr = null;
  try {
    nextDueDateStr =
      w11.isBusinessDay === true
        ? String(w11.localDate || w11.nextBusinessDay || '').substring(0, 10)
        : String(w11.nextBusinessDay || '').substring(0, 10);
    if (!nextDueDateStr || nextDueDateStr.length < 8) {
      results.push({ json: { skip: true, skipReason: 'W11 invalid date' } });
      continue;
    }
  } catch (e) {
    results.push({ json: { skip: true, skipReason: 'W11 failed: ' + String(e.message || e) } });
    continue;
  }
  results.push({ json: { ...ctx, nextDueDateStr } });
}
return results.length > 0 ? results : [{ json: { skip: true } }];

function safeNodeItems(nodeName) {
  try {
    return $(nodeName).all();
  } catch (e) {
    return [];
  }
}
function isLeadBlocked(ctx) {
  return ctx.blockAdvance === true || ctx.skipLead === true || ctx.dedupeCheckFailed === true;
}
const DEDUPE_FAIL = 'Dedupe check failed — skipped for production safety';
const ctxItems = $('Email Send — Ready for W11').all();
const failedLeads = new Set(
  safeNodeItems('Email Log Dedupe Error Handler').map((i) => String(i.json.leadId || '')).filter(Boolean)
);
const checkByIndex = {};
for (const item of $('Check Existing Email Log Task').all()) {
  const idx = item.pairedItem?.item ?? 0;
  checkByIndex[idx] = item.json || {};
}
const results = [];
for (let i = 0; i < ctxItems.length; i++) {
  const ctx = ctxItems[i].json;
  if (!ctx || !ctx.leadId) continue;
  if (failedLeads.has(String(ctx.leadId))) {
    continue;
  }
  const chk = checkByIndex[i];
  if (chk === undefined || chk.error || chk.errorMessage) {
    continue;
  }
  if (chk.Id) {
    const ok = String(chk.WhoId || '') === String(ctx.leadId) && String(chk.Subject || '') === String(ctx.emailLogSubject || '');
    if (!ok) {
      continue;
    }
    results.push({ json: { ...ctx, emailLogExists: true, dedupeCheckOk: true } });
  } else {
    results.push({ json: { ...ctx, emailLogExists: false, dedupeCheckOk: true } });
  }
}
return results.length > 0 ? results : [{ json: { skip: true } }];

const preSend = $('Preserve Pre-Send Context').all();
const sendOutputs = $input.all();
const results = [];

for (let i = 0; i < preSend.length; i++) {
  const ctx = preSend[i]?.json;
  if (!ctx || !ctx.leadId || ctx.skip) continue;

  results.push({
    json: {
      ...ctx,
      emailSentThisRun: true,
      emailComplete: false,
      emailSendOutput: sendOutputs[i]?.json || {},
    },
  });
}

return results.length > 0
  ? results
  : [
      {
        json: {
          skip: true,
          blockAdvance: true,
          skipReason:
            'Email sent or attempted, but Recover Context After Send found no pre-send context. Email log task was not created.',
        },
      },
    ];

