  ST_Day28: { callTask: true, smsTask: false, sendEmail: true, reviewTask: false },
  ST_Day42: { callTask: false, smsTask: true, sendEmail: true, reviewTask: true },
};
const SUBJECTS = {
  ST_Day0: 'Revisiting Our Conversation',
  ST_Day28: 'Still Worth Exploring?',
  ST_Day42: 'Should I Close the File?',
};
const EMAIL_BODIES = {
  ST_Day0: (fn) => '<p>Hi ' + fn + ',</p><p>I wanted to follow up on our previous conversations.</p><p>When we last connected, it sounded like there was interest in exploring ways to strengthen your customers experience while supporting operational goals.</p><p>I know priorities shift quickly, so I wanted to check whether these initiatives are still on your radar.</p><p>Would next week make sense for a brief conversation?</p>',
  ST_Day28: (fn) => '<p>Hi ' + fn + ',</p><p>Based on our previous discussions, I still believe there may be an opportunity to support your organization through a combination of customers-focused programs and engagement initiatives.</p><p>Is this something you are still evaluating, or would it make more sense for me to circle back later in the year?</p>',
  ST_Day42: (fn) => '<p>Hi ' + fn + ',</p><p>I know you are busy, so I will keep this brief.</p><p>Since I have not heard back, I am assuming this may not be a priority right now.</p><p>Rather than continue filling your inbox, I will close out my follow-up for the time being.</p><p>If this becomes a priority in the future, I would be happy to reconnect.</p>',
};
const buildSig = (sig, cl) => '<br><br>' + sig.replace('CALENDLY_PLACEHOLDER', cl);

const results = [];
for (const item of $input.all()) {
  const ctx = item.json;
  if (!ctx || !ctx.leadId) continue;
  const step = ctx.currentStep;
  const actions = ACTIONS[step] || {};
  const leadName = ctx.leadName || ((ctx.firstName || '') + ' ' + (ctx.lastName || '')).trim();
  const fn = String(ctx.firstName || 'there');
  const sig = String(ctx.colleagueSignatureHtml || '');
  const cl = String(ctx.calendlyLink || '');
  const emailSubject = actions.sendEmail ? SUBJECTS[step] || null : null;
  const bodyContent = actions.sendEmail && EMAIL_BODIES[step] ? EMAIL_BODIES[step](fn) : null;
  const emailBody = bodyContent ? bodyContent + buildSig(sig, cl) : null;
  const emailLogSubject = actions.sendEmail ? 'Email Sent — Stalled — ' + step + ' — ' + leadName : null;
  const callTaskSubject = actions.callTask ? 'Call Task — Stalled — ' + step + ' — ' + leadName : null;
  const smsTaskSubject = actions.smsTask
    ? (step === 'ST_Day42'
        ? 'Final SMS Task — Stalled — ' + step + ' — ' + leadName
        : 'SMS Task — Stalled — ' + step + ' — ' + leadName)
    : null;
  const reviewTaskSubject = actions.reviewTask ? 'Day 42 - Review lead status' : null;
  results.push({
    json: safetyDefaults({
      ...ctx,
      needsCallTask: !!actions.callTask,
      needsSmsTask: !!actions.smsTask,
      needsEmailSend: !!actions.sendEmail,
      needsReviewTask: !!actions.reviewTask,
      emailSubject,
      emailBody,
      emailLogSubject,
      callTaskSubject,
      smsTaskSubject,
      reviewTaskSubject,
      ccEmail: String(ctx.senderCcEmail || ctx.ccEmail || ''),
      callTaskComplete: !actions.callTask,
      smsTaskComplete: !actions.smsTask,
      reviewTaskComplete: !actions.reviewTask,
      emailComplete: !actions.sendEmail,
    }),
  });
}
return results.length > 0 ? results : [{ json: debugSkip({}, 'No leads reached Build Step Actions') }];

